1	/* eslint-disable bim-ai/no-hex-in-chrome -- pre-v3 hex literals; remove when this file is migrated in B4 Phase 2 */
2	/**
3	 * SKT-01 / SKT-02 / SKT-03 — Sketch authoring overlay.
4	 *
5	 * Mounts as an absolute overlay above `PlanCanvas` while a sketch session is
6	 * open. Renders the in-progress sketch as turquoise lines (Revit convention),
7	 * shows the validation status, and exposes Line / Rectangle / Pick Walls
8	 * drawing modes plus Finish ✓ / Cancel ✗ controls. Esc cancels.
9	 *
10	 * SKT-02 (Pick Walls) — clicking a wall in pick mode toggles it in/out of the
11	 * session's `picked_walls`; the server re-derives the sketch lines using the
12	 * configured offset mode and auto-trims corners.
13	 *
14	 * SKT-03 (validation feedback) — open vertices and self-intersections are
15	 * highlighted in red; a status panel lists all issues; Tab cycles between
16	 * issues; an "Auto-close" one-click fix joins a single open gap.
17	 *
18	 * Coordinate mapping is delegated to two callback refs supplied by the parent
19	 * canvas — that way we don't reimplement the orthographic camera math and stay
20	 * in sync with pan / zoom automatically.
21	 */
22	
23	import {
24	  type CSSProperties,
25	  type JSX,
26	  type RefObject,
27	  useCallback,
28	  useEffect,
29	  useMemo,
30	  useRef,
31	  useState,
32	} from 'react';
33	
34	import { hitTestWallAtMm, OffsetModeChip, type WallForPicking } from './SketchCanvasPickWalls';
35	import {
36	  addSketchLine,
37	  cancelSketchSession,
38	  finishSketchSession,
39	  getSketchSession,
40	  openSketchSession,
41	  pickWall,
42	  setPickWallsOffsetMode,
43	  type PickWallsOffsetMode,
44	  type SketchElementKind,
45	  type SketchSessionWire,
46	  type SketchValidationIssue,
47	  type SketchValidationState,
48	} from './sketchApi';
49	
50	const TURQUOISE = '#3fc5d3';
51	const TURQUOISE_FAINT = 'rgba(63, 197, 211, 0.45)';
52	const VERTEX_FILL = '#0e8b9c';
53	const ERROR_RED = '#ef4444';
54	const ERROR_GLOW = 'rgba(239, 68, 68, 0.35)';
55	
56	export type Point2D = { xMm: number; yMm: number };
57	
58	export type PointerToMm = (clientX: number, clientY: number) => Point2D | null;
59	export type MmToScreen = (pt: Point2D) => { x: number; y: number } | null;
