        {phase === 'tread_lines' && lineStart && hoverScreen && (() => {
          const ls = toScreen(lineStart);
          if (!ls) return null;
          return (
            <line
              x1={ls.x}
              y1={ls.y}
              x2={hoverScreen.x}
              y2={hoverScreen.y}
              stroke="var(--color-warning, #f59e0b)"
              strokeWidth={1.5}
              strokeDasharray="6 4"
            />
          );
        })()}
