        {hoverScreen && (
          <circle
            cx={hoverScreen.x}
            cy={hoverScreen.y}
            r={5}
            fill="none"
            stroke="var(--color-foreground, #e6edf6)"
            strokeWidth={1.5}
          />
        )}
      </svg>

