      <div
        style={{
          position: 'absolute',
          top: 12,
          left: '50%',
          transform: 'translateX(-50%)',
          background: 'var(--color-surface)',
          border: '1px solid var(--color-border)',
          borderRadius: 'var(--radius-sm)',
          padding: '4px 12px',
          fontSize: 'var(--text-sm)',
          color: 'var(--color-foreground)',
          pointerEvents: 'none',
          userSelect: 'none',
        }}
      >
        {phase === 'boundary'
          ? 'Phase A: Draw boundary polygon — click to add vertices, click near first vertex or press Enter to close'
          : 'Phase B: Draw tread lines — click start, click end'}
      </div>

      {/* Comfort advisory chip */}
      {phase === 'tread_lines' && riserCount > 0 && (
        <div
          style={{
            position: 'absolute',
            top: 52,
            left: '50%',
            transform: 'translateX(-50%)',
            background: advisoryOk ? 'var(--color-success)' : 'var(--color-destructive)',
            borderRadius: 'var(--radius-sm)',
            padding: '3px 10px',
            fontSize: 'var(--text-sm)',
            color: 'var(--color-surface)',
            pointerEvents: 'none',
            transition: 'background var(--ease-paper)',
            userSelect: 'none',
          }}
        >
          {advisoryOk
            ? `✓ ${Math.round(avgTread)}×${Math.round(avgRiser)} mm — EU proxy OK`
            : [
                !treadOk && `Tread ${Math.round(avgTread)} mm < 260 mm min`,
                !riserOk && `Riser ${Math.round(avgRiser)} mm > 190 mm max`,
              ]
                .filter(Boolean)
                .join(' · ')}
        </div>
      )}

      {/* Mode toggle & action buttons */}
      <div
        style={{
          position: 'absolute',
          bottom: 16,
          left: '50%',
          transform: 'translateX(-50%)',
          display: 'flex',
          gap: 8,
          alignItems: 'center',
        }}
      >
        {/* Segmented mode toggle */}
        <div
          style={{
            display: 'flex',
            border: '1px solid var(--color-border)',
            borderRadius: 'var(--radius-sm)',
            overflow: 'hidden',
            fontSize: 'var(--text-sm)',
          }}
        >
          <button
            type="button"
            style={{
              padding: '4px 12px',
              background:
                phase === 'boundary' ? 'var(--color-accent)' : 'var(--color-surface)',
              color:
                phase === 'boundary' ? 'var(--color-surface)' : 'var(--color-foreground)',
              border: 'none',
              cursor: boundary.length === 0 ? 'default' : 'pointer',
              fontSize: 'inherit',
            }}
            onClick={() => setPhase('boundary')}
          >
            Boundary
          </button>
          <button
            type="button"
            style={{
              padding: '4px 12px',
              background:
                phase === 'tread_lines' ? 'var(--color-accent)' : 'var(--color-surface)',
              color:
                phase === 'tread_lines'
                  ? 'var(--color-surface)'
                  : boundary.length >= 3
                    ? 'var(--color-foreground)'
                    : 'var(--color-muted-foreground)',
              border: 'none',
              cursor: boundary.length >= 3 ? 'pointer' : 'not-allowed',
              fontSize: 'inherit',
            }}
            disabled={boundary.length < 3}
            onClick={() => boundary.length >= 3 && setPhase('tread_lines')}
          >
            Tread lines
          </button>
        </div>

        <button
          type="button"
          disabled={!canFinish || busy}
          onClick={() => void handleFinish()}
          style={{
            padding: '4px 16px',
            background: canFinish ? 'var(--color-accent)' : 'var(--color-muted)',
            color: 'var(--color-surface)',
            border: 'none',
            borderRadius: 'var(--radius-sm)',
            fontSize: 'var(--text-sm)',
            cursor: canFinish && !busy ? 'pointer' : 'not-allowed',
          }}
        >
          {busy ? '…' : '✓ Finish'}
        </button>
        <button
          type="button"
          onClick={handleCancel}
          style={{
            padding: '4px 16px',
            background: 'var(--color-surface)',
            color: 'var(--color-foreground)',
            border: '1px solid var(--color-border)',
            borderRadius: 'var(--radius-sm)',
            fontSize: 'var(--text-sm)',
            cursor: 'pointer',
          }}
        >
          ✗ Cancel
        </button>
      </div>
    </div>
  );
}

