            onClick={() => setPhase('boundary')}
          >
            Boundary
          </button>
          <button
            type="button"
            style={{
              padding: '4px 12px',
              background:
                phase === 'tread_lines' ? 'var(--color-accent)' : 'var(--color-surface)',
              color:
                phase === 'tread_lines'
                  ? 'var(--color-surface)'
                  : boundary.length >= 3
                    ? 'var(--color-foreground)'
                    : 'var(--color-muted-foreground)',
              border: 'none',
              cursor: boundary.length >= 3 ? 'pointer' : 'not-allowed',
              fontSize: 'inherit',
            }}
            disabled={boundary.length < 3}
            onClick={() => boundary.length >= 3 && setPhase('tread_lines')}
          >
            Tread lines
          </button>
        </div>

        <button
          type="button"
          disabled={!canFinish || busy}
          onClick={() => void handleFinish()}
          style={{
            padding: '4px 16px',
            background: canFinish ? 'var(--color-accent)' : 'var(--color-muted)',
            color: 'var(--color-surface)',
            border: 'none',
            borderRadius: 'var(--radius-sm)',
            fontSize: 'var(--text-sm)',
            cursor: canFinish && !busy ? 'pointer' : 'not-allowed',
          }}
        >
          {busy ? '…' : '✓ Finish'}
        </button>
        <button
          type="button"
          onClick={handleCancel}
          style={{
            padding: '4px 16px',
            background: 'var(--color-surface)',
            color: 'var(--color-foreground)',
            border: '1px solid var(--color-border)',
            borderRadius: 'var(--radius-sm)',
            fontSize: 'var(--text-sm)',
            cursor: 'pointer',
          }}
        >
          ✗ Cancel
        </button>
      </div>
    </div>
  );
}

